/**
 * @summary Record a swipe on a destination
 */
export const getRecordSwipeUrl = () => {
  return `/api/swipes`;
};

export const recordSwipe = async (
  recordSwipeBody: RecordSwipeBody,
  options?: RequestInit,
): Promise<SwipeResult> => {
  return customFetch<SwipeResult>(getRecordSwipeUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(recordSwipeBody),
  });
};

export const getRecordSwipeMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof recordSwipe>>,
    TError,
    { data: BodyType<RecordSwipeBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof recordSwipe>>,
  TError,
  { data: BodyType<RecordSwipeBody> },
  TContext
> => {
  const mutationKey = ["recordSwipe"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof recordSwipe>>,
    { data: BodyType<RecordSwipeBody> }
  > = (props) => {
    const { data } = props ?? {};

    return recordSwipe(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type RecordSwipeMutationResult = NonNullable<
  Awaited<ReturnType<typeof recordSwipe>>
>;
export type RecordSwipeMutationBody = BodyType<RecordSwipeBody>;
export type RecordSwipeMutationError = ErrorType<unknown>;

